    <rect x="20" y="72" width="300" height="46" rx="8" fill="#3f3f46"/>
    <text x="170" y="94" fill="#e4e4e7" font-size="12.5" text-anchor="middle" font-weight="700">Strategy's bitcoin-sale policy</text>
    <text x="170" y="112" fill="#a1a1aa" font-size="12" text-anchor="middle">→ an "avoidable" two-way risk</text>
